class BoundedStack:
    def __init__(self, cap):
        self.cap = cap
        self.items = []

    def push(self, x):
        if len(self.items) >= self.cap:
            return len(self.items)
        self.items.append(x)
        return len(self.items)

    def pop(self):
        if not self.items:
            return None
        return self.items.pop()

