def format_phone(digits):
    cleaned = ''.join(c for c in digits if c.isdigit())
    if len(cleaned) != 10:
        return digits
    return '(' + cleaned[0:3] + ') ' + cleaned[3:6] + '-' + cleaned[6:10]

